{
#if (DELAY_TIMER)
    // 配置基本定时器参数
    BTMR->CR1.Word = BTMR_CR1_MODE;  // CR1：设置定时器模式
    BTMR->PSC = tpsc - 1;            // PSC：设置预分频器值
    BTMR->ARR = tcnt - 1;            // ARR：设置自动重载值
    BTMR->CNT = 0;                   // CNT：清零计数器
    BTMR->EGR = 1;                   // EGR：生成更新事件，重新初始化计数器

    // 使能计数器并等待定时完成
    BTMR->CR1.CEN = 1;               // CR1.CEN：使能计数器
    while(!BTMR->RIF && BTMR->CR1.CEN); // RIF：等待更新中断标志置位
    BTMR->ICR = 1;                   // ICR：清除中断标志

    // 清除定时器模式
    BTMR->CR1.Word = 0;              // CR1：禁用计数器
#else
    // 使用SysTick定时器延时
    uint32_t temp;

    SysTick->LOAD = tcnt * tpsc - 1;    // 设置重载值
    SysTick->VAL  = 0x00;               // 清零当前值
    SysTick->CTRL = SysTick_CTRL_CLKSOURCE_Msk | SysTick_CTRL_ENABLE_Msk; // 使能SysTick

    do
    {
        temp = SysTick->CTRL;           // 读取控制状态寄存器
    } while((temp & SysTick_CTRL_ENABLE_Msk) && !(temp & SysTick_CTRL_COUNTFLAG_Msk));

    SysTick->CTRL &= ~SysTick_CTRL_ENABLE_Msk; // 禁用SysTick
    SysTick->VAL   = 0x00;              // 清零当前值
#endif
}

{
    volatile uint32_t reg_sclk, reg_dpll;

    /************************************************************************
     **************             禁用时钟和电源              **************
     ************************************************************************/
    // 等待Flash缓存空闲
    while(SYSCFG->ACC_CCR_BUSY);

    // 关闭DPLL，如果当前使用DPLL则先切换系统时钟
    reg_sclk = RCC->CFG.Word;      // CFG：读取系统时钟配置
    if ((reg_sclk & 0x0F) == 4/*SCLK_PLL*/)
    {
        RCC->CFG.Word = (reg_sclk & ~0x0F) | 2/*SCLK_HSE*/; // CFG：切换到HSE时钟
    }

    reg_dpll = APBMISC->DPLL_CTRL.Word;
    APBMISC->DPLL_CTRL.Word = 0;   // DPLL_CTRL：禁用DPLL

    /************************************************************************
     **************              进入深度睡眠               **************
     ************************************************************************/
    SCB->SCR |= (SCB_SCR_SLEEPDEEP_Msk); // SCR：配置深度睡眠模式
    __WFI();                           // 等待中断，进入睡眠
    SCB->SCR &= ~(SCB_SCR_SLEEPDEEP_Msk); // SCR：退出深度睡眠模式

    /************************************************************************
     **************             恢复时钟和电源              **************
     ************************************************************************/
    // 恢复DPLL和系统时钟
    APBMISC->DPLL_CTRL.Word = reg_dpll; // DPLL_CTRL：恢复DPLL设置
    // if enable dpll2_en, delay 50us wait dpll clk stable
    if (reg_dpll & APBMISC_DPLL2_EN_BIT)
        boot_delayUs(50);            // 如果启用DPLL2，等待时钟稳定
    RCC->CFG.Word = reg_sclk;        // CFG：恢复系统时钟配置

    // 复位Flash控制器，恢复单线模式
    // 2022.11.05 --- wq.
    RCC->AHBRST_CTRL.FSHC_RSTREQ = 1; // AHBRST_CTRL：请求Flash复位
    RCC->AHBRST_CTRL.FSHC_RSTREQ = 0; // AHBRST_CTRL：释放Flash复位
}

{
    // 获取复位原因
    uint16_t ret_st = (RCC->CHIP_RST_ST_CLR.Word & 0xFF); // CHIP_RST_ST_CLR：读取复位状态

    // 获取掉电唤醒源
    if (AON->PMU_CTRL.POWEROFF_LOG)
    {
        ret_st |= ((AON->PMU_WKUP_ST.Word & 0x0F) << 8); // PMU_WKUP_ST：读取唤醒状态
        APBMISC->POWEROFF_LOG_CLR = 1;                   // POWEROFF_LOG_CLR：清除掉电日志
    }

    // 清除状态标志
    RCC->CHIP_RST_ST_CLR.Word = (0xFF << 8);            // CHIP_RST_ST_CLR：清除复位状态
    APBMISC->AON_PMU_CTRL.Word |= (1 << APBMISC_WKUP_ST_CLR_POS) | (1 << APBMISC_AON_PMU_INT_CLR_POS);

    return ret_st;
}

{
    // 配置定时器参数
    BTMR->CR1.Word = CR1_ONE_MODE;  // CR1：设置单次模式
    BTMR->PSC = tpsc - 1;           // PSC：设置预分频器
    BTMR->ARR = tcnt - 1;           // ARR：设置自动重载值
    BTMR->CNT = 0;                  // CNT：清零计数器
    BTMR->EGR = 1;                  // EGR：生成更新事件

    // 使能计数器并等待定时完成
    BTMR->CR1.CEN = 1;              // CR1.CEN：使能计数器
    while(!BTMR->RIF && BTMR->CR1.CEN); // RIF：等待中断标志
    BTMR->ICR = 1;                  // ICR：清除中断标志

    // 清除定时器模式
    BTMR->CR1.Word = 0;             // CR1：禁用计数器
}

{
    // 配置16MHz晶体振荡器
    AON->XOSC16M_CTRL.EN_LDO_SEL = 0;  // XOSC16M_CTRL：LDO由XOSC16M_EN控制
    AON->PMU_CTRL.OSC_EN_RUN = 1;      // PMU_CTRL：使能运行模式振荡器
    APBMISC->XOSC16M_CTRL.EN_XO16MBUF = 1; // XOSC16M_CTRL：使能晶体缓冲器

    // 等待振荡器稳定
    boot_delayUs(2000);
}

