{
    volatile uint32_t reg_sclk, reg_dpll;

    /************************************************************************
     **************             禁用时钟和电源              **************
     ************************************************************************/
    // 等待Flash缓存空闲
    while(SYSCFG->ACC_CCR_BUSY);

    // close dpll, First switch sysclk if dpll used.
    reg_sclk = RCC->CFG.Word;      // .SYSCLK_SW; bit[3:0]

    // 切换到RC16M时钟
    reg_sclk = RCC->CFG.Word;
    RCC->CFG.Word = (reg_sclk & ~0x0F) | 1/*SCLK_HSI*/; // CFG：切换到RC16M时钟

    // 关闭外部晶体缓冲器，配置低功耗模式
    APBMISC->XOSC16M_CTRL.EN_XO16MBUF = 0;
    APBMISC->AON_PMU_CTRL.OSC_EN_DP = 1;
    // XOSC16M_LP=0,about 150uA
    APBMISC->XOSC16M_CTRL.XOSC16M_LP = 1;

    /**************************************************************/
    // 降低功耗配置
    uint32_t reg_usb_ctrl = SYSCFG->USB_CTRL.Word;
    SYSCFG->USB_CTRL.Word &= ~(0x01 << SYSCFG_DIG_USB_RXEN_POS); // USB_CTRL：禁用USB接收

    // 降低核心LDO偏置电流
    AON->PMU_ANA_CTRL.LDO12_IBSEL = 0x1F; // PMU_ANA_CTRL：设置LDO偏置

    RF->ANA_PWR_CTRL.Word = 0x007F7F00; // ANA_PWR_CTRL：禁用PLL时钟
    RF->ANA_EN_CTRL.Word = 0x00060000;  // ANA_EN_CTRL：禁用带隙基准
    /**************************************************************/

    reg_dpll = APBMISC->DPLL_CTRL.Word;
    APBMISC->DPLL_CTRL.Word = 0;   // DPLL_CTRL：禁用DPLL

    /************************************************************************
     **************              进入深度睡眠               **************
     ************************************************************************/
    SCB->SCR |= (SCB_SCR_SLEEPDEEP_Msk);
    __WFI();
    SCB->SCR &= ~(SCB_SCR_SLEEPDEEP_Msk);

    /************************************************************************
     **************             恢复时钟和电源              **************
     ************************************************************************/
    // 恢复外部晶体和时钟配置
    APBMISC->XOSC16M_CTRL.EN_XO16MBUF = 1;
    APBMISC->XOSC16M_CTRL.XOSC16M_LP = 0;

    /**************************************************************/
    // 恢复功耗配置
    AON->PMU_ANA_CTRL.LDO12_IBSEL = 0x10;

    RF->ANA_EN_CTRL.Word = 0x00070000;  // ANA_EN_CTRL：启用带隙基准
    RF->ANA_PWR_CTRL.Word = 0x07FF7F08; // ANA_PWR_CTRL：启用PLL时钟
    SYSCFG->USB_CTRL.Word = reg_usb_ctrl;
    /**************************************************************/

    // 恢复DPLL和系统时钟
    APBMISC->DPLL_CTRL.Word = reg_dpll;
    if (reg_dpll & APBMISC_DPLL2_EN_BIT)
        btmr_delay(16, 50);        // 等待DPLL稳定

    RCC->CFG.Word = reg_sclk;      // CFG：恢复系统时钟

    // Reset FSHC, Restore Single Line
    // 2022.11.05 --- wq.
//    RCC->AHBRST_CTRL.FSHC_RSTREQ = 1;
//    RCC->AHBRST_CTRL.FSHC_RSTREQ = 0;
}

{
    volatile uint32_t reg_sclk, reg_dpll;

    /************************************************************************
     **************             禁用时钟和电源              **************
     ************************************************************************/
    // 等待Flash缓存空闲
    while(SYSCFG->ACC_CCR_BUSY);

    // 关闭DPLL，如果当前使用DPLL则先切换系统时钟
    reg_sclk = RCC->CFG.Word;      // CFG：读取系统时钟配置
    if (dis_xo16m)
    {
        APBMISC->AON_PMU_CTRL.OSC_EN_DP = 0;
        // if ((reg_sclk & 0x0F) == 4/*SCLK_PLL*/)
        {
            RCC->CFG.Word = (reg_sclk & ~0x0F) | 2/*SCLK_HSE*/; // CFG：切换到HSE时钟
        }
    }
    else
    {
        RCC->CFG.Word = (reg_sclk & ~0x0F) | 1/*SCLK_HSI*/; // CFG：切换到RC16M时钟

        // 关闭外部晶体缓冲器，配置低功耗模式
        APBMISC->XOSC16M_CTRL.EN_XO16MBUF = 0;
        APBMISC->AON_PMU_CTRL.OSC_EN_DP   = 1;
        // XOSC16M_LP=0,about 150uA
        APBMISC->XOSC16M_CTRL.XOSC16M_LP  = 1;
    }

    /**************************************************************/
    // 降低功耗配置
    uint32_t reg_usb_ctrl  = SYSCFG->USB_CTRL.Word;
    SYSCFG->USB_CTRL.Word &= ~(0x01 << SYSCFG_DIG_USB_RXEN_POS); // USB_CTRL：禁用USB接收


    // ECO. LDO_DPLL_EN Current Leakage Bug.
    bool is_c2 = (0x904A3A8F == RD_32(0x18000F40));

    AON_PMU_ANA_CTRL_TypeDef reg_pmu_ana = AON->PMU_ANA_CTRL;

    reg_pmu_ana.LDO12_IBSEL = 0x1F;
    reg_pmu_ana.Word       &= ~(is_c2 << PMU_ANA_CTRL_DPLL_LDO_POS);
    AON->PMU_ANA_CTRL       = reg_pmu_ana;

    // 降低核心LDO偏置电流
//    AON->PMU_ANA_CTRL.LDO12_IBSEL = 0x1F; // PMU_ANA_CTRL：设置LDO偏置

    RF->ANA_PWR_CTRL.Word = 0x007F7F00; // ANA_PWR_CTRL：禁用PLL时钟
    RF->ANA_EN_CTRL.Word  = 0x00060000; // ANA_EN_CTRL：禁用带隙基准
    /**************************************************************/

    reg_dpll = APBMISC->DPLL_CTRL.Word;
    APBMISC->DPLL_CTRL.Word = 0;   // DPLL_CTRL：禁用DPLL

    /************************************************************************
     **************              进入深度睡眠               **************
     ************************************************************************/
    SCB->SCR |= (SCB_SCR_SLEEPDEEP_Msk); // SCR：配置深度睡眠模式
    __WFI();                           // 等待中断，进入睡眠
    SCB->SCR &= ~(SCB_SCR_SLEEPDEEP_Msk); // SCR：退出深度睡眠模式
    /**************************************************************/

    if (!dis_xo16m)
    {
        // 恢复外部晶体和时钟配置
        APBMISC->XOSC16M_CTRL.EN_XO16MBUF = 1;
        APBMISC->XOSC16M_CTRL.XOSC16M_LP  = 0;
    }

    reg_pmu_ana.LDO12_IBSEL = 0x10;
    reg_pmu_ana.Word |= (is_c2 << PMU_ANA_CTRL_DPLL_LDO_POS);
    AON->PMU_ANA_CTRL = reg_pmu_ana;

    // 恢复功耗配置
//    AON->PMU_ANA_CTRL.LDO12_IBSEL = 0x10;

    RF->ANA_EN_CTRL.Word  = 0x00070000; // ANA_EN_CTRL：启用带隙基准
    RF->ANA_PWR_CTRL.Word = 0x07FF7F08; // ANA_PWR_CTRL：启用PLL时钟
    SYSCFG->USB_CTRL.Word = reg_usb_ctrl;
    /**************************************************************/

    /************************************************************************
     **************             恢复时钟和电源              **************
     ************************************************************************/
    // 恢复DPLL和系统时钟
    APBMISC->DPLL_CTRL.Word = reg_dpll; // DPLL_CTRL：恢复DPLL设置
    // if enable dpll2_en, delay 50us wait dpll clk stable
    if (reg_dpll & APBMISC_DPLL2_EN_BIT)
        bootDelayUs(50);            // 如果启用DPLL2，等待时钟稳定
    RCC->CFG.Word = reg_sclk;        // CFG：恢复系统时钟配置

    // 复位Flash控制器，恢复单线模式
    // 2022.11.05 --- wq.
    RCC->AHBRST_CTRL.FSHC_RSTREQ = 1; // AHBRST_CTRL：请求Flash复位
    RCC->AHBRST_CTRL.FSHC_RSTREQ = 0; // AHBRST_CTRL：释放Flash复位
}

